const Q_BIOLOGY_2016=[{"id": "objective>Biology>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled <strong>IV</strong> is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">endodermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">piliferous layer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root hair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epidermis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled(IV) is the piliferous layer. <br/> It is the piliferous layer is the outer covering of the root.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The structure that conducts water round the plant body is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Xylem is responsible for the conduction of water and dissolved mineral salts. Xylem is the part labelled I.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between a herbivore and the bacteria that lives in its caecum is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between a herbivore and the bacteria that live in its caecum is mutualism. Mutualism is a type of symbiotic relationship where both organisms benefit. In this case, the bacteria help the herbivore digest plant material, and in return, the bacteria receive a warm, nutrient-rich environment to live in.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an animal that exhibits counter shading is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">snake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chameleon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tilapia fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butterfly</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Countershading is a method of camouflage in which an animal's coloration is darker on the upper side and lighter on the underside of the body. This reduces the animal's visibility from different angles, both from above and below. Tilapia fish is an example of an animal that exhibits countershading. The other options do not typically exhibit countershading.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of Chaetae on Earthworm is for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">locomotion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chaetae in earthworms are tiny, bristle-like structures that the earthworm uses for locomotion. They help the earthworm to grip the soil and move forward. They are not involved in respiration, reproduction, or excretion.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of four chambered heart is a characteristic feature of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pisces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amphibians</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A four-chambered heart is a characteristic feature of mammals. This type of heart allows for complete separation of oxygenated and deoxygenated blood, which makes the circulatory system of mammals more efficient. Pisces (fish), reptilia (reptiles), and amphibians do not have a four-chambered heart.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sum total of adaptive changes that have taken place over a very long period of time is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adaptation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Evolution is the process by which different kinds of living organisms are thought to have developed and diversified from earlier forms during the history of the earth. It is the sum total of adaptive changes that have taken place over a very long period of time.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of prolactin hormone in human is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stimulates ovulation in females</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases basal metabolic rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulates the development of female sex organ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">induces milk production in pregnant women</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prolactin is a hormone produced by the pituitary gland in the brain. It's primary role is to promote breast milk production (lactation) in women after childbirth. Hence, it induces milk production in pregnant women.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of organism that reproduce by binary fission is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volvox</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paramecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spirogyra</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Binary fission is a type of asexual reproduction where an organism splits into two offspring. Paramecium, a single-celled protist, reproduces by binary fission.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Gritty when wet. <br/>  II. High air content. <br/> III. High capillarity. <br/> IV. Fine particles. <br/>  Which of the above are properties of clay soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay soil is known for its fine particles and it becomes gritty when wet. Clay soil has a high cation-exchange capacity, meaning it can hold onto nutrients and water much better than sandy soil. The high capillarity refers to the ability of the soil to draw water upwards from a water source. This is not a characteristic of clay soil. Clay soil does not have high air content, it is actually known for being dense and heavy, with low porosity.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The male reproductive organ of a flower is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calyx</div>", "<div style=\"font-family:Cambria;font-size:17px;\">androecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gynoecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corolla</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The male reproductive organ of a flower is the androecium. The androecium is the collective term for all the male organs of a flower, which includes the stamens. Each stamen is made up of a filament (stalk) and an anther, which produces pollen grains. The calyx and corolla are the outer parts of a flower, and the gynoecium is the female reproductive organ.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> Which of the organisms in the food chain above have the lowest number?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Grasshoppers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lizards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hawks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grasses</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the trophic level goes higher, the number of organisms decreases .  <br/>  Grasses → Grasshoppers → Lizards → Hawks  <br/>  The number of grasses eaten by lizards  and finally, the number of lizards eaten by the hawks is greater than the number of hawks.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transfer of pollen grains from the anther to the stigma is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">placentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">germination</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The transfer of pollen grains from the anther (the part of the stamen that produces and contains pollen) to the stigma (the part of the pistil where pollen germinates) of a flower is referred to as pollination. Fertilization is the fusion of the male gametes (from the pollen) with the female gametes (in the ovule). Placentation refers to the arrangement of ovules within the ovary, and germination is the process by which a plant grows from a seed or similar structure.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ that is responsible for detoxification in the body is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bladder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spleen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liver is the organ that is responsible for detoxification in the body. It does this by metabolizing and removing harmful substances from the bloodstream. The other options, bladder, spleen, and kidney, have different functions. The bladder stores urine, the spleen filters blood, and the kidneys filter blood to produce urine.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the structure which translocate manufactured food from the site of production to where it is used up is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lenticel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food vacuole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the phloem is the structure that translocates manufactured food from the site of production (usually the leaves) to where it is used or stored. The phloem is part of the plant's vascular system, which also includes the xylem. The xylem transports water and minerals from the roots to the rest of the plant, not food. Lenticels and food vacuoles have different functions.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the eye that is sensitive to light is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sclerotic layer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optic nerve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conjunctiva</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The retina is the part of the eye that is sensitive to light. It contains cells called photoreceptors which convert light into electrical signals. These signals are then sent to the brain via the optic nerve where they are interpreted as visual images. The sclerotic layer, optic nerve, and conjunctiva have different functions in the eye.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The possession of hollow and light bones is an adaptive feature of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lizards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fishes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insects</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds have hollow and light bones. This is an adaptive feature that allows them to fly. The hollow bones are strong and provide the necessary support for flight, while their lightness reduces the bird's overall weight, making it easier for them to stay aloft.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD"}, {"id": "objective>Biology>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The condition in which the skin is non-pigmented because of lack of melanin is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">haemophilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">baldness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">albinism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cretism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Albinism is a condition that causes the skin, hair, or eyes to have little or no color. Albinism is caused by mutations (changes) in several genes. The mutations may be passed down through families. Melanin is the pigment that gives color to the skin, hair, and eyes. In albinism, the cells that produce melanin do not work properly because of the mutations.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Organisms at the cell level of organization include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paramecium, hydra and spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amoeba, paramecium and chlamydomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheek cell, volvox and chlamydomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheek cell, amoeba and spirogyra</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organisms at the cell level of organization include amoeba, paramecium and chlamydomonas. These are all unicellular organisms, meaning they are made up of a single cell. In contrast, organisms like hydra and volvox are multicellular, meaning they are made up of many cells.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The net result of the influence of natality and mortality rate of organisms in a given habitat is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population growth rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The net result of the influence of natality (birth rate) and mortality (death rate) of organisms in a given habitat is referred to as population growth rate. This is because the difference between the birth rate and the death rate determines whether the population is growing, shrinking, or remaining stable.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>NOT</strong> true of plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They respond slowly to stimuli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have autotrophic mode of nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have apical growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have developed excretory system</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants do not have a developed excretory system like animals. Instead, they get rid of waste products through different methods such as storing them in leaves that fall off, or releasing them into the soil through their roots.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><em>Trypanosome gambinese</em> is a parasite transmitted to human by infected.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">housefly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tsetse fly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blackfly</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Trypanosoma gambiense </span>, the parasite that causes African sleeping sickness, is transmitted to humans by the tsetse fly. When an infected tsetse fly bites a human, the parasite is transferred into the human's bloodstream.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Severe diarrhoea, dehydration and weakness of the body are symptoms of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">malaria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dysentery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cholera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cholera is an infectious disease that causes severe watery diarrhea, which can lead to dehydration and even death if untreated. It is caused by eating food or drinking water contaminated with a bacterium called <span style=\"font-style:italic;\"> Vibrio cholerae </span>.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structure which allows selective movement of materials in and out of the cell is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cytoplasm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitochondria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cell membrane, also known as the plasma membrane, is a biological membrane that separates the interior of all cells from the outside environment. It is selectively permeable to ions and organic molecules and controls the movement of substances in and out of cells.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In multicellular organisms, a group of numerous, similar cells arranged together  to perform specific function is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an organ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an organism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In multicellular organisms, a tissue is an ensemble of similar cells and their extracellular matrix from the same origin that together carry out a specific function. Organs are then formed by the functional grouping together of multiple tissues.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable medium for the growth of saprophytic organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in an environment without moisture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on other living organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on inorganic substances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on decomposing materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Saprophytic organisms are organisms that feed on dead and decaying organic matter. Therefore, the most suitable medium for their growth is on decomposing materials.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The raw materials of photosynthesis are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glucose and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide and oxygen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The raw materials for photosynthesis are carbon dioxide (carbon(IV)oxide) and water.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Voluntary actions are controlled by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebrum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Voluntary actions are those actions which are under the conscious control of the brain. They are controlled by the cerebrum, the largest part of the brain, which is responsible for all voluntary actions in the body.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A condition in which a harmless organism resembles a distasteful or harmful one to scare its enemies is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cryptic colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">camouflage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">batesian mimicry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warning colouration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Batesian mimicry is a form of mimicry where a harmless species has evolved to imitate the warning signals of a harmful species directed at a predator of them both. It is named after the English naturalist Henry Walter Bates, after his work in the rainforests of Brazil.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Celebro spinal meningitis is caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><em>Salmonella sp.</em></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><em>Vibrio sp.</em></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><em>Meningococcus sp.</em></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><em>Treponema sp.</em></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cerebrospinal meningitis, also known as meningococcal meningitis, is a bacterial form of meningitis, a serious infection of the meninges that affects the brain membrane. It can cause severe brain damage and is fatal in 50% of cases if untreated. It is caused by the bacterium Neisseria meningitis , also known as meningococcus.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A typical example of a thallophyta is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liverwort</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fern</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thallophyta is a division of the plant kingdom that includes all the lower plants i.e., the algae, fungi, lichens, and bacteria. A typical example of a thallophyta is spirogyra. Spirogyra is a genus of filamentous green algae of the order Zygnematales, named for the helical or spiral arrangement of the chloroplasts that is characteristic of the species.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The character that determines physical appearance and helps to identify the individual of a population is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">physiological variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discontinuous variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphological variations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Morphological variations refer to the differences in physical characteristics among individuals of the same species. These variations can include differences in size, shape, color, and other observable traits.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Movement of minerals and chemical compounds within a plant occurs during</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">translocation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Translocation in plants refers to the movement of organic compounds, such as sugars, amino acids, and minerals, from the leaves (where they are produced through photosynthesis) to other parts of the plant.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>NOT</strong> an example of transmittable character in human things?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shape of head, nose and ear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Body stature or shape</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Colour of skin, hair and eye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Life span or pattern of growth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Life span or pattern of growth is not a transmittable character in human beings. Transmittable characters are traits that can be passed from parents to offspring through genes. While certain aspects of growth and development can be influenced by genetics, the overall life span and pattern of growth are largely determined by environmental factors and individual lifestyle choices, not genetics.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ that is responsible for excretion in insects is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flame cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nephridia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malpighian tubules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In insects, the organ responsible for excretion is the Malpighian tubules. These tubules float in the haemolymph and collect waste products, which are then excreted out of the body. Flame cells are excretory structures in flatworms, nephridia are found in earthworms, and contractile vacuoles are found in some single-celled organisms.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phloem tissues is made up of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wood parenchyma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tracheids and wood fibres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sieve tubes and companion cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem vessels</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phloem tissue is made up of sieve tubes and companion cells. Sieve tubes are responsible for the transport of sugars and other nutrients throughout the plant, while companion cells help to maintain the sieve tubes. Wood parenchyma, tracheids and wood fibres, and xylem vessels are all components of xylem tissue, not phloem.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dental formula i-3/3, c-1/1, pm-4/4, m-2/3 is found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dental formula i-3/3, c-1/1, pm-4/4, m-2/3 is found in dogs. This formula represents the number of incisors (i), canines (c), premolars (pm), and molars (m) in one half of the mouth. Humans have a dental formula of i-2/2, c-1/1, pm-2/2, m-3/3, while cows have a dental formula of i-0/4, c-0/1, pm-3/3, m-3/3, and rabbits have a dental formula of i-2/1, c-0/0, pm-3/2, m-3/3.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ecological factor that is common to arboreal habitat</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">edaphic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ecological factor common to arboreal habitat is altitude. Arboreal habitats are habitats that are located in the trees. Altitude is a factor because the types of trees that can grow in an area, and therefore the type of arboreal habitat, can change with altitude.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The local biome which is characterised by little or no rainfall, high temperature and few grasses is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical grassland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea savanna</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The local biome which is characterised by little or no rainfall, high temperature and few grasses is the desert. Deserts are known for their harsh conditions, including extreme temperatures and lack of water.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : DESERT"}, {"id": "objective>Biology>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pairs of genes on the position of a chromosome that control contrasting characters is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allelomorphs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heredity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pairs of genes on the position of a chromosome that control contrasting characters are known as allelomorphs. In genetics, an allelomorph is an alternative form of a gene (one member of a pair) that is located at a specific position on a specific chromosome. These DNA codings determine distinct traits that can be passed on from parents to offspring through sexual reproduction. The concept of allelomorphs is fundamental to the study of genetics.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man who has the ability to taste phenylthiocarbamide marries a woman who can not taste phenylthiocarbamide. The probability of their children to taste phenylthiocarbamide</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75:25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25:75</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50:50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability to taste phenylthiocarbamide (PTC) is a dominant trait. Therefore, if one parent has the ability to taste PTC (Tt) and the other parent does not (tt), the possible genotypes of their children would be Tt and tt. This results in a 50:50 probability of their children being able to taste PTC.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The association between a remora fish and a shark is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amensalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between a remora fish and a shark is an example of commensalism. Commensalism is a type of symbiotic relationship where one organism benefits and the other is neither harmed nor benefited. In this case, the remora fish benefits by getting a free ride and access to leftover food, while the shark is not affected.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the human tooth that is sensitive to heat and cold is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pulp cavity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enamel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dentine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pulp cavity of the tooth contains the nerve endings and blood vessels, which makes it sensitive to heat and cold. The enamel and dentine are hard tissues that protect the pulp cavity, while the gum is the soft tissue that surrounds and supports the teeth. The pulp cavity is sensitive to heat and cold due to the presence of: <br/>  <br/> - Nerve endings that transmit sensory information <br/> - Blood vessels that respond to temperature changes <br/> - Soft tissue that expands and contracts with temperature changes <br/>  <br/> This sensitivity helps protect the tooth and surrounding tissues, but can also cause discomfort or pain if the tooth is damaged or infected.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In centipedes, the exchange of gases is carried out through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">body surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lung books</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In centipedes, the exchange of gases is carried out through the trachea. The trachea is a system of tubes that allows for the direct exchange of gases into the tissues. This is different from humans and other vertebrates, where gas exchange occurs in the lungs.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of tall trees, broad leaves and buttress roots are characteristic features of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of tall trees, broad leaves and buttress roots are characteristic features of the tropical rainforest. These features allow the plants to maximize sunlight absorption, which is abundant in the tropical rainforest. The buttress roots provide additional support to the tall trees.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A viral disease of man is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">syphilis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tuberculosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small pox</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cholera</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Small pox is a viral disease of man. It is caused by the variola virus. The other diseases listed, syphilis, tuberculosis, and cholera, are caused by bacteria, not viruses.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle that controls all life activities of the cell is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitochondria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vacuole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is the organelle that controls all life activities of the cell. It contains the cell's DNA and regulates the cell's activities such as metabolism, growth, and reproduction by controlling protein synthesis.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms does not exhibit adaptive colouration?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chameleon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stick insect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Giraffe</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive coloration is a type of camouflage where an organism's coloration or pattern allows it to blend in with its environment. Among the options, the Giraffe does not exhibit adaptive coloration. While its pattern may provide some camouflage in certain environments, it is not a primary function as it is with the other organisms listed.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Northern Guinea savanna can be found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Borno state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kwara state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plateau state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Delta state</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Northern Guinea savanna can be found in Borno state. The Guinea Savanna is a tropical grassland ecoregion of West Africa. In Nigeria, it is found in the northern part of the country, including Borno state.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA"}, {"id": "objective>Biology>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms is not found in the marine habitat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shrimps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">snails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tilapia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tilapia is a freshwater fish and is not found in marine habitats. Marine habitats are saltwater environments like oceans and seas. Tilapia, on the other hand, are found in freshwater environments like rivers, lakes, and ponds.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}];
